  defaultExpandedProjectPaths?: string[];
}): ReactElement {
  const [expandedProjectPaths, setExpandedProjectPaths] = useState<Set<string>>(() => new Set(defaultExpandedProjectPaths));

  const toggleProject = useCallback((projectPath: string): void => {
