    void loadProjects();
    void window.relay.codex.status().then(setCodexStatus);
  }, [loadProjects]);

  useEffect(() => {
    void loadBoard();
  }, [loadBoard]);

  useEffect(() => {
    if (selectedPath) void refreshProjectGitMetadata(selectedPath, true);
  }, [refreshProjectGitMetadata, selectedPath]);

  useEffect(() => {
    const refreshSelectedGitMetadata = (): void => {
      if (selectedPath) void refreshProjectGitMetadata(selectedPath, true);
    };
