13	export const getActiveTicketMention = (value: string, selectionStart: number, selectionEnd = selectionStart): TicketMentionToken | null => {
14	  if (selectionStart !== selectionEnd) return null;
15	  const beforeCursor = value.slice(0, selectionStart);
16	  const mentionStart = beforeCursor.lastIndexOf("@");
17	  if (mentionStart < 0) return null;
18	
19	  const previous = mentionStart > 0 ? value[mentionStart - 1] : "";
20	  if (previous && /[\w./-]/.test(previous)) return null;
21	
22	  const query = beforeCursor.slice(mentionStart + 1);
23	  if (invalidMentionQuery.test(query)) return null;
24	
25	  return {
26	    start: mentionStart,
27	    end: selectionStart,
28	    query
29	  };
30	};
31	
32	export const filterTicketReferenceCandidates = (
33	  candidates: TicketReferenceCandidate[],
34	  query: string,
35	  limit = 8
36	): TicketReferenceCandidate[] => {
37	  const normalizedQuery = normalizeSearch(query);
38	  if (!normalizedQuery) return candidates.slice(0, limit);
39	
40	  return candidates
41	    .map((candidate) => {
42	      const title = normalizeSearch(candidate.title);
43	      const path = normalizeSearch(candidate.relativePath);
44	      const status = normalizeSearch(candidate.columnName || candidate.status);
45	      const score =
46	        title.startsWith(normalizedQuery)
47	          ? 0
48	          : title.includes(normalizedQuery)
49	            ? 1
50	            : path.includes(normalizedQuery)
51	              ? 2
52	              : status.includes(normalizedQuery)
53	                ? 3
54	                : null;
55	
56	      return score === null ? null : { candidate, score };
57	    })
58	    .filter((item): item is { candidate: TicketReferenceCandidate; score: number } => item !== null)
59	    .sort((a, b) => a.score - b.score || a.candidate.title.localeCompare(b.candidate.title))
60	    .slice(0, limit)
61	    .map((item) => item.candidate);
62	};
